import React, { useContext, useEffect, useState } from "react";
import { useParams, Navigate, useNavigate } from "react-router-dom";
import { UserContext } from "../context/UserContext";
import axios from "axios";
import TestImg from "./TestImg";

const OneItemList = () => {
  let { id } = useParams();
  const { user, ready } = useContext(UserContext);
  const [itemData, setItemData] = useState({});
  const navigate = useNavigate();
  useEffect(() => {
    if (user) {
      const fetchData = async () => {
        try {
          axios.defaults.headers.common.Authorization = `Bearer ${user?.token}`;
          const response = await axios.get(`/items/getbyid/${id}`);
          setItemData(...response.data);
        } catch (error) {
          console.log(error);
        }
      };
      fetchData();
    }
  }, [user]);

  if (ready && !user) {
    return <Navigate to={"/register"} />;
  }

  const bookItem = async () => {
    if (user && itemData) {
      try {
        const response = await axios.post("/booking/item", {
          owner: itemData.owner,
          itemid: itemData._id,
          buyer: user.userId,
        });
        if (response.status === 200) {
          await axios.patch("/items/sold", {
            itemid: itemData._id,
            sold: true,
          });
          navigate("/");
        }
      } catch (error) {
        if (error.response && error.response.data) {
          console.log(error.response.data);
        } else {
          console.log(error.message);
        }
      }
    }
  };

  return (
    <div>
      {/* <div className=''>
            <h1>Single Item</h1>
            
            <h2>{itemData.iname}</h2>
            <div>
           
            </div>
            <h2>{itemData.imrp}</h2>
            <button className='cursor-pointer px-6 py-3 bg-green-500' onClick={bookItem}>Buy Now</button>
        </div> */}

      <div className="flex gap-2 mt-10 w-full">

        <div className="grow max-w-[1000px]">
          {itemData.photos?.map((pic, index) => (
            <div className=" flex  gap-2 justify-center" key={index}>
              <img
                className="rounded-2xl w-full object-cover"
                alt="img not found"
                src={"http://localhost:5000/" + pic}
              />
            </div>
          ))}
        </div>

        <div className="grow  bg-red-500   ">
          <div className="sticky top-0">
            <div>
                
            </div>
          </div>
        </div>  

      </div>

      <div className="mt-96">
        sac
      </div>
      {/* <TestImg itemData={itemData} /> */}
    </div>
  );
};

export default OneItemList;
